    for i := 0; i <= n; i++ {
        dp[i] = make([]int64, k+1)
        for j := 0; j <= k; j++ {
            dp[i][j] = INF
        }
    }

    for i := 1; i <= n; i++ {
        dp[i][1] = prefix_xor[i]
    }

    k_val := int(k)
